/**
 * Upload a chart screenshot for analysis context
 * @summary Upload chart screenshot
 */
export const getUploadScreenshotUrl = () => {
  return `/api/upload/screenshot`;
};

export const uploadScreenshot = async (
  uploadScreenshotBody: UploadScreenshotBody,
  options?: RequestInit,
): Promise<UploadResult> => {
  const formData = new FormData();
  formData.append(`file`, uploadScreenshotBody.file);
  if (uploadScreenshotBody.symbol !== undefined) {
    formData.append(`symbol`, uploadScreenshotBody.symbol);
  }
  if (uploadScreenshotBody.timeframe !== undefined) {
    formData.append(`timeframe`, uploadScreenshotBody.timeframe);
  }

  return customFetch<UploadResult>(getUploadScreenshotUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

